PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE imports (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    file_name TEXT,
    platform TEXT,
    r2_key TEXT,
    import_date DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE orders (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    order_id TEXT,
    platform TEXT,
    status TEXT, -- success, cancel, refund
    revenue REAL,
    sku TEXT,
    qty INTEGER,
    import_id INTEGER, created_at TEXT, fee REAL DEFAULT 0, profit REAL DEFAULT 0, product_name TEXT DEFAULT '', shop TEXT DEFAULT '', order_type TEXT DEFAULT 'normal', cost_invoice REAL DEFAULT 0, cost_real REAL DEFAULT 0, profit_invoice REAL DEFAULT 0, profit_real REAL DEFAULT 0, tax_flat REAL DEFAULT 0, tax_income REAL DEFAULT 0, cancel_reason TEXT, return_fee REAL DEFAULT 0, raw_revenue REAL DEFAULT 0, order_date TEXT DEFAULT '', fee_platform  REAL DEFAULT 0, fee_payment   REAL DEFAULT 0, fee_affiliate REAL DEFAULT 0, fee_ads       REAL DEFAULT 0, fee_piship    REAL DEFAULT 0, fee_service   REAL DEFAULT 0, fee_packaging REAL DEFAULT 0, fee_operation REAL DEFAULT 0, fee_labor     REAL DEFAULT 0, is_first_sku INTEGER DEFAULT 0, user_id TEXT, shop_id TEXT,
    FOREIGN KEY(import_id) REFERENCES imports(id)
);
CREATE TABLE products (sku TEXT PRIMARY KEY, product_name TEXT, cost_invoice REAL DEFAULT 0, cost_real REAL DEFAULT 0, is_combo INTEGER DEFAULT 0, combo_items TEXT, combo_qty INTEGER DEFAULT 1, user_id TEXT, shop_id TEXT);
CREATE TABLE combo_items (id INTEGER PRIMARY KEY AUTOINCREMENT, combo_sku TEXT, component_sku TEXT, quantity INTEGER, FOREIGN KEY(combo_sku) REFERENCES products(sku), FOREIGN KEY(component_sku) REFERENCES products(sku));
CREATE TABLE sku_mapping (  platform_sku TEXT,  internal_sku TEXT );
CREATE TABLE sku_alias (  id INTEGER PRIMARY KEY AUTOINCREMENT,  platform_sku TEXT,  internal_sku TEXT );
CREATE TABLE cost_settings (  id INTEGER PRIMARY KEY AUTOINCREMENT,  cost_key TEXT,  cost_value REAL,  cost_type TEXT , cost_name TEXT DEFAULT '', calc_type TEXT DEFAULT 'per_order', platform  TEXT DEFAULT '', shop      TEXT DEFAULT '', user_id TEXT);
CREATE TABLE platform_reports (id INTEGER PRIMARY KEY AUTOINCREMENT, platform TEXT NOT NULL, shop TEXT NOT NULL DEFAULT '', report_month TEXT NOT NULL, report_type TEXT NOT NULL DEFAULT 'income', file_name TEXT NOT NULL, r2_key TEXT NOT NULL, uploaded_at TEXT NOT NULL DEFAULT (datetime('now')), gross_revenue REAL DEFAULT 0, refund_amount REAL DEFAULT 0, net_product_revenue REAL DEFAULT 0, platform_subsidy REAL DEFAULT 0, seller_voucher REAL DEFAULT 0, co_funded_voucher REAL DEFAULT 0, shipping_net REAL DEFAULT 0, fee_commission REAL DEFAULT 0, fee_payment REAL DEFAULT 0, fee_service REAL DEFAULT 0, fee_affiliate REAL DEFAULT 0, fee_piship_sfr REAL DEFAULT 0, fee_handling REAL DEFAULT 0, fee_total REAL DEFAULT 0, compensation REAL DEFAULT 0, tax_vat REAL DEFAULT 0, tax_pit REAL DEFAULT 0, tax_total REAL DEFAULT 0, total_payout REAL DEFAULT 0, raw_data TEXT DEFAULT '{}', fee_ads INTEGER DEFAULT 0, user_id TEXT, shop_id TEXT);
CREATE TABLE purchase_invoices (   id           INTEGER PRIMARY KEY AUTOINCREMENT,   supplier     TEXT,   invoice_no   TEXT UNIQUE,   invoice_date TEXT,   total_amount INTEGER DEFAULT 0,   item_count   INTEGER DEFAULT 0,   r2_key       TEXT,   created_at   TEXT DEFAULT (datetime('now')) , buyer TEXT DEFAULT '', items_json TEXT DEFAULT '[]');
CREATE TABLE invoice_sku_map (   id            INTEGER PRIMARY KEY AUTOINCREMENT,   invoice_name  TEXT UNIQUE,   sku           TEXT,   created_at    TEXT DEFAULT (datetime('now')) );
CREATE TABLE sku_groups (   id         INTEGER PRIMARY KEY AUTOINCREMENT,   group_name TEXT UNIQUE,   skus       TEXT DEFAULT '[]',   created_at TEXT DEFAULT (datetime('now')) , user_id TEXT);
CREATE TABLE orders_v2 (   id            INTEGER PRIMARY KEY AUTOINCREMENT,   order_id      TEXT NOT NULL UNIQUE,   platform      TEXT DEFAULT '',   shop          TEXT DEFAULT '',   order_date    TEXT DEFAULT '',   order_type    TEXT DEFAULT 'normal',   revenue       REAL DEFAULT 0,   raw_revenue   REAL DEFAULT 0,   cost_invoice  REAL DEFAULT 0,   cost_real     REAL DEFAULT 0,   fee           REAL DEFAULT 0,   profit_invoice REAL DEFAULT 0,   profit_real   REAL DEFAULT 0,   tax_flat      REAL DEFAULT 0,   tax_income    REAL DEFAULT 0,   fee_platform  REAL DEFAULT 0,   fee_payment   REAL DEFAULT 0,   fee_affiliate REAL DEFAULT 0,   fee_ads       REAL DEFAULT 0,   fee_piship    REAL DEFAULT 0,   fee_service   REAL DEFAULT 0,   fee_packaging REAL DEFAULT 0,   fee_operation REAL DEFAULT 0,   fee_labor     REAL DEFAULT 0,   cancel_reason TEXT,   return_fee    REAL DEFAULT 0,   shipped       INTEGER DEFAULT 0,   created_at    TEXT DEFAULT (datetime('now')) );
CREATE TABLE order_items (   id           INTEGER PRIMARY KEY AUTOINCREMENT,   order_id     TEXT NOT NULL,   sku          TEXT DEFAULT '',   product_name TEXT DEFAULT '',   qty          INTEGER DEFAULT 1,   revenue_line REAL DEFAULT 0,   cost_real    REAL DEFAULT 0,   cost_invoice REAL DEFAULT 0,   FOREIGN KEY(order_id) REFERENCES orders_v2(order_id) );
CREATE TABLE jobs (   id INTEGER PRIMARY KEY AUTOINCREMENT,   user_id TEXT,   shop_name TEXT,   platform TEXT,   month INTEGER,   year INTEGER,   status TEXT DEFAULT 'pending',   file_url TEXT,   created_at DATETIME DEFAULT CURRENT_TIMESTAMP , task_type TEXT, r2_file_key TEXT, log_text TEXT, started_at DATETIME, completed_at DATETIME, shop_id TEXT, scheduled_at DATETIME);
CREATE TABLE users (     id TEXT PRIMARY KEY,     username TEXT UNIQUE NOT NULL,     password_hash TEXT NOT NULL,     role TEXT DEFAULT 'user',     license_expire_at DATETIME,     created_at DATETIME DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE shops (     id TEXT PRIMARY KEY,     user_id TEXT NOT NULL,     platform TEXT NOT NULL,     shop_name TEXT NOT NULL,     status TEXT DEFAULT 'active',     profile_dir TEXT,            download_dir TEXT,         created_at DATETIME DEFAULT CURRENT_TIMESTAMP );
DELETE FROM sqlite_sequence;
CREATE INDEX idx_orders_date ON orders(created_at);
CREATE INDEX idx_orders_sku ON orders(sku);
CREATE UNIQUE INDEX idx_order_sku ON orders(order_id, sku);
CREATE UNIQUE INDEX idx_cost_key ON cost_settings(cost_key);
CREATE INDEX idx_products_sku ON products(sku);
CREATE INDEX idx_orders_platform ON orders(platform);
CREATE UNIQUE INDEX idx_platform_reports_unique ON platform_reports(platform, report_month, file_name);
CREATE INDEX idx_orders_v2_date     ON orders_v2(order_date);
CREATE INDEX idx_orders_v2_platform ON orders_v2(platform);
CREATE INDEX idx_orders_v2_shop     ON orders_v2(shop);
CREATE INDEX idx_order_items_order  ON order_items(order_id);
CREATE INDEX idx_order_items_sku    ON order_items(sku);
CREATE INDEX idx_jobs_status ON jobs(status);
